(function(cartLink) {
  // Create badge element
  let badge = cartLink.querySelector('.cart-badge');
  if (!badge) {
    badge = document.createElement('span');
    badge.className = 'cart-badge';
    Object.assign(badge.style, {
      position: 'absolute',
      top: '-6px',
      right: '-8px',
      background: '#4F46E5',
      color: '#fff',
      fontSize: '10px',
      fontWeight: '700',
      width: '18px',
      height: '18px',
      borderRadius: '50%',
      display: 'none',
      alignItems: 'center',
