      fontFamily: "'Outfit', sans-serif",
      transition: 'transform 0.4s cubic-bezier(0.16, 1, 0.3, 1)',
      zIndex: '20',
      boxShadow: '0 2px 8px rgba(79, 70, 229, 0.4)',
    });
    cartLink.style.position = 'relative';
    cartLink.appendChild(badge);
  }

  // Fetch cart count on load
  async function updateCartCount() {
    try {
      const res = await fetch('/api/method/webshop.webshop.shopping_cart.cart.get_cart_count', {
        method: 'GET',
        headers: { 'X-Frappe-CSRF-Token': frappe?.csrf_token || '' }
      });
      const data = await res.json();
      const count = data.message || 0;
      if (count > 0) {
        badge.textContent = count > 99 ? '99+' : count;
        badge.style.display = 'flex';
      } else {
        badge.style.display = 'none';
      }
    } catch(e) { /* silent */ }
  }
  updateCartCount();

  // Listen for cart changes and bounce
  document.addEventListener('show-toast', (e) => {
    if (e.detail && e.detail.type === 'success' && e.detail.message && e.detail.message.includes('cart')) {
      updateCartCount();
      badge.style.transform = 'scale(1.4)';
      setTimeout(() => { badge.style.transform = 'scale(1)'; }, 300);
    }
  });})(this);
